import React from 'react';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
}

function App() {
const [usuario, setUsuario] = React.useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  await Api.get("").then((response)=>setUsuario(response.data));
}

  return (
    <div style={container}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>
      <div>
        <li>
          <div>
            {usuario.map((usuario)=>{
              return (
                <div>
                  <h1 key={usuario.id}> {usuario.nome}</h1>
                  </div>
              )
            })}
          </div>
        </li>
      </div>
    </div>
  );
}

export default App;

const container={
  display:"flex",
  color:"black",
  backgroundColor:"red",
  alignItems:"center",
  justifyContent:"center",
 }
